export class NotFoundError extends Error{name="NotFoundError";code="ENOENT";constructor(r){super(`ENOENT: No such file or directory, ${r}`)}}export class PermissionError extends Error{name="PermissionError";code="EPERM";constructor(r){super(`EPERM: Operation not permitted, ${r}`)}}export class DirectoryError extends Error{name="DirectoryError";code="EISDIR";constructor(r){super(`EISDIR: Illegal operation on a directory, ${r}`)}}export class NotEmptyError extends Error{name="NotEmptyError";code="ENOTEMPTY";constructor(r){super(`ENOTEMPTY: Directory not empty, ${r}`)}}